INSERT INTO `wp_burst_query_stats` VALUES (1,'6a4404012fa22e6d','SELECT /*+ MAX_EXECUTION_TIME(30000) */ COUNT(DISTINCT statistics.uid) AS visitors, COUNT(DISTINCT statistics.ID) AS pageviews, AVG( statistics.time_on_page ) AS avg_time_on_page FROM wp_burst_statistics AS statistics INNER JOIN wp_burst_sessions AS sessions ON statistics.session_id = sessions.ID WHERE statistics.time BETWEEN 1783036800 AND 1783123199',0.000473,0.000473,0.000473,1783108498,1,1);
INSERT INTO `wp_burst_query_stats` VALUES (2,'a1c3a12211d3b728','SELECT /*+ MAX_EXECUTION_TIME(30000) */ COUNT(DISTINCT(uid)) FROM wp_burst_statistics AS statistics INNER JOIN wp_burst_sessions AS sessions ON statistics.session_id = sessions.ID WHERE statistics.time BETWEEN 1783107898 AND 1783112098 AND ( (time + time_on_page / 1000 + 60 + 240) > 1783108498)',0.000456,0.000456,0.000456,1783108498,1,1);
INSERT INTO `wp_burst_query_stats` VALUES (3,'94f51aedd30537de','SELECT /*+ MAX_EXECUTION_TIME(30000) */ statistics.page_url AS page_url, COUNT(DISTINCT statistics.ID) AS pageviews FROM wp_burst_statistics AS statistics WHERE statistics.time BETWEEN 1783036800 AND 1783123199 GROUP BY page_url ORDER BY pageviews DESC LIMIT 1',0.000111,0.000111,0.000111,1783108498,1,1);
INSERT INTO `wp_burst_query_stats` VALUES (4,'2fcc6e47ff594304','SELECT /*+ MAX_EXECUTION_TIME(30000) */ sessions.referrer AS referrer, COUNT(DISTINCT statistics.ID) AS pageviews FROM wp_burst_statistics AS statistics INNER JOIN wp_burst_sessions AS sessions ON statistics.session_id = sessions.ID WHERE statistics.time BETWEEN 1783036800 AND 1783123199 AND sessions.referrer != \'\' AND sessions.referrer IS NOT NULL GROUP BY referrer ORDER BY pageviews DESC LIMIT 1',0.000223,0.000223,0.000223,1783108498,1,1);
INSERT INTO `wp_burst_query_stats` VALUES (5,'40c6bff0f4d9542b','SELECT /*+ MAX_EXECUTION_TIME(30000) */ COUNT(DISTINCT statistics.uid) AS visitors, COUNT(DISTINCT statistics.ID) AS pageviews, AVG( statistics.time_on_page ) AS avg_time_on_page FROM wp_burst_statistics AS statistics INNER JOIN wp_burst_sessions AS sessions ON statistics.session_id = sessions.ID WHERE statistics.time BETWEEN 1782432000 AND 1783036799',0.000133,0.000133,0.000133,1783108504,1,7);
INSERT INTO `wp_burst_query_stats` VALUES (6,'0a90ae62cc57ffe8','SELECT /*+ MAX_EXECUTION_TIME(30000) */ statistics.page_url AS page_url, COUNT(DISTINCT statistics.ID) AS pageviews FROM wp_burst_statistics AS statistics WHERE statistics.time BETWEEN 1782432000 AND 1783036799 GROUP BY page_url ORDER BY pageviews DESC LIMIT 1',0.000061,0.000061,0.000061,1783108504,1,7);
INSERT INTO `wp_burst_query_stats` VALUES (7,'95f55e65deeb2072','SELECT /*+ MAX_EXECUTION_TIME(30000) */ sessions.referrer AS referrer, COUNT(DISTINCT statistics.ID) AS pageviews FROM wp_burst_statistics AS statistics INNER JOIN wp_burst_sessions AS sessions ON statistics.session_id = sessions.ID WHERE statistics.time BETWEEN 1782432000 AND 1783036799 AND sessions.referrer != \'\' AND sessions.referrer IS NOT NULL GROUP BY referrer ORDER BY pageviews DESC LIMIT 1',0.00008,0.00008,0.00008,1783108504,1,7);
INSERT INTO `wp_burst_query_stats` VALUES (8,'c98b8b99ddf66b16','SELECT /*+ MAX_EXECUTION_TIME(30000) */ time+time_on_page / 1000 AS active_time, sessions.referrer AS utm_source, page_url, time, time_on_page, uid, page_id, locations.country_code FROM wp_burst_statistics AS statistics INNER JOIN wp_burst_sessions AS sessions ON statistics.session_id = sessions.ID LEFT JOIN wp_burst_locations AS locations ON sessions.city_code = locations.city_code WHERE statistics.time BETWEEN 1783144643 AND 1783150043 ORDER BY active_time DESC LIMIT 100',0.000396,0.000396,0.000396,1783146443,1,1);
INSERT INTO `wp_burst_query_stats` VALUES (9,'fc35189b7a5d0c05','SELECT /*+ MAX_EXECUTION_TIME(30000) */ COUNT(DISTINCT statistics.uid) AS visitors, COUNT(DISTINCT statistics.ID) AS pageviews, DATE_FORMAT(FROM_UNIXTIME(time + 25200), \'%Y-%m-%d\') AS period FROM wp_burst_statistics AS statistics INNER JOIN wp_burst_sessions AS sessions ON statistics.session_id = sessions.ID WHERE statistics.time BETWEEN 1782518400 AND 1783123199 GROUP BY period ORDER BY period',0.001173,0.001173,0.001173,1783146455,1,7);
INSERT INTO `wp_burst_query_stats` VALUES (10,'1136c1c2351eb5c4','SELECT /*+ MAX_EXECUTION_TIME(30000) */ COUNT(DISTINCT statistics.uid) AS visitors, COUNT(DISTINCT statistics.ID) AS pageviews, COUNT( DISTINCT statistics.session_id ) AS sessions, COUNT(DISTINCT CASE WHEN sessions.first_time_visit = 1 THEN statistics.uid END) AS first_time_visitors, AVG( statistics.time_on_page ) AS avg_time_on_page, ROUND(COALESCE(COUNT(DISTINCT CASE WHEN sessions.bounce = 1 THEN sessions.ID END) / NULLIF(COUNT(DISTINCT sessions.ID), 0), 0) * 100, 2) AS bounce_rate FROM wp_burst_statistics AS statistics INNER JOIN wp_burst_sessions AS sessions ON statistics.session_id = sessions.ID WHERE statistics.time BETWEEN 1782518400 AND 1783123199',0.002315,0.002315,0.002315,1783146455,1,7);
INSERT INTO `wp_burst_query_stats` VALUES (11,'eba03115659bdab2','SELECT /*+ MAX_EXECUTION_TIME(30000) */ COUNT(DISTINCT statistics.ID) AS pageviews, COUNT( DISTINCT statistics.session_id ) AS sessions, COUNT(DISTINCT statistics.uid) AS visitors, ROUND(COALESCE(COUNT(DISTINCT CASE WHEN sessions.bounce = 1 THEN sessions.ID END) / NULLIF(COUNT(DISTINCT sessions.ID), 0), 0) * 100, 2) AS bounce_rate FROM wp_burst_statistics AS statistics INNER JOIN wp_burst_sessions AS sessions ON statistics.session_id = sessions.ID WHERE statistics.time BETWEEN 1781913600 AND 1782518399',0.001587,0.001587,0.001587,1783146455,1,7);
INSERT INTO `wp_burst_query_stats` VALUES (12,'918d8f031cde06f3','SELECT /*+ MAX_EXECUTION_TIME(30000) */ COUNT(DISTINCT CASE WHEN sessions.bounce = 1 THEN sessions.ID END) AS bounces FROM wp_burst_statistics AS statistics INNER JOIN wp_burst_sessions AS sessions ON statistics.session_id = sessions.ID WHERE statistics.time BETWEEN 1782518400 AND 1783123199',0.00089,0.00089,0.00089,1783146455,1,7);
INSERT INTO `wp_burst_query_stats` VALUES (13,'0abeb8081df1dee5','SELECT /*+ MAX_EXECUTION_TIME(30000) */ sessions.device_id, COUNT(sessions.device_id) AS count FROM wp_burst_statistics AS statistics INNER JOIN wp_burst_sessions AS sessions ON statistics.session_id = sessions.ID WHERE statistics.time BETWEEN 1782518400 AND 1783123199 AND sessions.device_id > 0 GROUP BY device_id',0.000322,0.000322,0.000322,1783146456,1,7);
INSERT INTO `wp_burst_query_stats` VALUES (14,'bd34f537e5377e71','SELECT /*+ MAX_EXECUTION_TIME(30000) */ sessions.device_id, sessions.browser_id, sessions.platform_id, COUNT(*) AS count FROM wp_burst_statistics AS statistics INNER JOIN wp_burst_sessions AS sessions ON statistics.session_id = sessions.ID WHERE statistics.time BETWEEN 1782518400 AND 1783123199 AND sessions.browser_id > 0 AND sessions.device_id > 0 GROUP BY device_id, browser_id, platform_id ORDER BY count DESC',0.000675,0.000675,0.000675,1783146456,1,7);
INSERT INTO `wp_burst_query_stats` VALUES (15,'54b81276e921f60b','SELECT /*+ MAX_EXECUTION_TIME(30000) */ statistics.page_url AS page_url, COUNT(DISTINCT statistics.ID) AS pageviews, COUNT(DISTINCT statistics.uid) AS visitors, ROUND(COALESCE(COUNT(DISTINCT CASE WHEN sessions.bounce = 1 THEN sessions.ID END) / NULLIF(COUNT(DISTINCT sessions.ID), 0), 0) * 100, 2) AS bounce_rate FROM wp_burst_statistics AS statistics INNER JOIN wp_burst_sessions AS sessions ON statistics.session_id = sessions.ID WHERE statistics.time BETWEEN 1782518400 AND 1783123199 GROUP BY page_url ORDER BY bounce_rate DESC',0.002342,0.002342,0.002342,1783146456,1,7);
INSERT INTO `wp_burst_query_stats` VALUES (16,'eb5f1b585e9cb7ed','SELECT /*+ MAX_EXECUTION_TIME(30000) */ sessions.referrer AS referrer, COUNT(DISTINCT statistics.uid) AS visitors, ROUND(COALESCE(COUNT(DISTINCT CASE WHEN sessions.bounce = 1 THEN sessions.ID END) / NULLIF(COUNT(DISTINCT sessions.ID), 0), 0) * 100, 2) AS bounce_rate, COUNT(DISTINCT goals.ID) AS conversions FROM (SELECT statistics.ID, statistics.time, statistics.page_url, statistics.page_id, statistics.page_type, statistics.uid, statistics.time_on_page, statistics.session_id FROM wp_burst_statistics AS statistics INNER JOIN wp_burst_sessions AS sessions ON statistics.session_id = sessions.ID WHERE statistics.time BETWEEN 1782518400 AND 1783123199 AND sessions.referrer != \'\' AND sessions.referrer IS NOT NULL) AS statistics INNER JOIN wp_burst_sessions AS sessions ON statistics.session_id = sessions.ID LEFT JOIN wp_burst_goal_statistics AS goals ON statistics.ID = goals.statistic_id WHERE statistics.time BETWEEN 1782518400 AND 1783123199 GROUP BY referrer ORDER BY conversions DESC',0.000514,0.000514,0.000514,1783146456,1,7);
INSERT INTO `wp_burst_query_stats` VALUES (17,'d1c0dc1a60da5b3b','SELECT /*+ MAX_EXECUTION_TIME(30000) */ statistics.page_url AS page_url, AVG( statistics.time_on_page ) AS avg_time_on_page FROM wp_burst_statistics AS statistics INNER JOIN wp_burst_sessions AS sessions ON statistics.session_id = sessions.ID WHERE statistics.time BETWEEN 1782518400 AND 1783123199 AND statistics.time_on_page > 0 AND statistics.page_url != \'\' GROUP BY page_url ORDER BY avg_time_on_page DESC LIMIT 10',0.000617,0.000617,0.000617,1783146470,1,7);
INSERT INTO `wp_burst_query_stats` VALUES (18,'','SELECT s.search AS term, COUNT(*) AS volume, MAX(ss.result_count) AS results FROM wp_burst_statistics_searches AS ss INNER JOIN wp_burst_searches AS s ON s.ID = ss.search_id WHERE ss.statistic_id IS NOT NULL AND ss.created BETWEEN 1782518400 AND 1783123199 GROUP BY ss.search_id, s.search ORDER BY volume DESC LIMIT 100',0.002202,0.002202,0.002202,1783146470,1,0);
