INSERT INTO `wp_posts` VALUES (12,0,'2026-07-03 16:49:31','2026-07-03 16:49:31','<!-- wp:nu/hero-billboard {\"eyebrow\":\"WordPress Research Fellows\",\"heading\":\"Build. Test. Ship.\",\"image\":\"hero.jpg\"} /-->\n\n<!-- wp:nu/pillars {\"heading\":\"A deep commitment to your research success\",\"intro\":\"Discover the value of a summer spent doing real WordPress research, and the mentorship, funding, and support behind every fellow along the way.\",\"items\":[\"network|Gain real-world experience|On a transformative research fellowship, you work full time in a small track team, shipping real WordPress tooling the department relies on every day.\",\"medal|Earn a paid fellowship|Every fellow receives a competitive 10-week stipend, and the program office connects you with scholarships, travel grants, and publication support.\",\"pyramid|Advance your career trajectory|Research and mentorship help you expand your knowledge, get published, and stand out to employers and graduate programs alike.\"]} /-->\n\n<!-- wp:nu/journey-cards {\"label\":\"Your research journey\",\"cards\":[\"collab.jpg|Fellows collaborating in a lab|Explore research opportunities|Search across our tracks — plugin architecture, editor UX, performance, security, and accessibility — and find the problem you want to own.|Explore the program|about-the-program\",\"mentor2.jpg|A fellow and mentor reviewing work together|Find a faculty mentor|Our faculty are leaders in their fields, and their guidance plays an enormous role in your research. See who you could be working with.|Meet the team|highlights-team\",\"fellows.jpg|Fellows presenting a project|Discover funding and deadlines|A paid 10-week stipend, plus awards that provide experiences, resources, and funding. Get info on eligibility, deadlines, and more.|Apply now|apply-eligibility\"]} /-->\n','Home','A 10-week paid summer fellowship where undergraduate Software Engineering students build, test, and ship real WordPress tooling alongside faculty mentors.','publish','closed','closed','','home','','','2026-07-03 21:11:23','2026-07-03 21:11:23','',0,'http://localhost:10005/home/',0,'page','',0);
